def func(self):
    query = str(self.args or "").strip().lower()
    if query == "fish":
        self.args = "fishing"
        query = "fishing"
    if query == "warrior":
        if hasattr(self.caller, "get_warrior_help_text"):
            self.msg_help(self.caller.get_warrior_help_text())
            return
    super().func()
